import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';

type Product = {
  id: string;
  name: string;
  price: number;
  category: 'Men' | 'Women' | 'Accessories' | 'Shoes';
