    name: 'Wool Beanie',
    price: 22,
    category: 'Accessories',
    image: 'https://images.unsplash.com/photo-1539533113208-8ffc39e9c1ae?w=900&q=80&auto=format&fit=crop',
    rating: 4.3,
    colors: ['#1f2937', '#dc2626'],
