    colors: ['#f59e0b', '#0ea5e9'],
  },
];

const categories: Array<'All' | 'Men' | 'Women' | 'Accessories' | 'Shoes'> = [
  'All',
  'Men',
  'Women',
  'Accessories',
  'Shoes',
];

const ProductList: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [active, setActive] = useState<'All' | 'Men' | 'Women' | 'Accessories' | 'Shoes'>('All');
  const [search, setSearch] = useState('');
  const [sort, setSort] = useState<'featured' | 'price-asc' | 'price-desc' | 'rating'>('featured');
  const [cartCount, setCartCount] = useState<number>(0);
  const [toast, setToast] = useState<string>('');
  const [selected, setSelected] = useState<Product | null>(null);
  const [quickColor, setQuickColor] = useState<string>('');
  const highlightRef = useRef<string | null>(null);

  useEffect(() => {
    setCartCount(readCart().reduce((a, b) => a + b.quantity, 0));
  }, []);

  useEffect(() => {
    const timer = setTimeout(() => setToast(''), 1800);
    return () => clearTimeout(timer);
  }, [toast]);

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const cat = params.get('category');
    const hl = params.get('highlight');
    if (cat && categories.includes(cat as any)) {
      setActive(cat as any);
    }
    if (hl) {
      highlightRef.current = hl;
      setTimeout(() => {
        const el = document.getElementById(`prod-${hl}`);
        if (el) {
          el.scrollIntoView({ behavior: 'smooth', block: 'center' });
          el.classList.add('ring-4', 'ring-blue-400');
          setTimeout(() => el.classList.remove('ring-4', 'ring-blue-400'), 1400);
        }
      }, 300);
    }
  }, [location.search]);

  const filtered = useMemo(() => {
    let arr = [...allProducts];
    if (active !== 'All') {
      arr = arr.filter((p) => p.category === active);
    }
    if (search.trim()) {
      const q = search.toLowerCase();
      arr = arr.filter((p) => p.name.toLowerCase().includes(q) || p.category.toLowerCase().includes(q));
    }
    if (sort === 'price-asc') arr.sort((a, b) => a.price - b.price);
    if (sort === 'price-desc') arr.sort((a, b) => b.price - a.price);
    if (sort === 'rating') arr.sort((a, b) => b.rating - a.rating);
    return arr;
  }, [active, search, sort]);

  const addToCart = (product: Product, qty: number = 1) => {
    const cart = readCart();
    const existing = cart.find((c) => c.id === product.id);
    if (existing) {
      existing.quantity += qty;
    } else {
      cart.push({ id: product.id, name: product.name, price: product.price, image: product.image, quantity: qty });
    }
    writeCart(cart);
    setCartCount(cart.reduce((a, b) => a + b.quantity, 0));
    setToast(`${product.name} added to cart`);
  };

  const Navbar: React.FC = () => {
    return (
