            <span className="inline-flex h-8 w-8 rounded-xl bg-gradient-to-tr from-blue-500 via-fuchsia-500 to-amber-400" />
            <span className="font-bold text-gray-900 text-lg">Vibrato Cloth Co.</span>
          </div>
          <nav className="hidden md:flex items-center gap-6 text-sm text-gray-700">
            <Link to="/" className="hover:text-blue-600 transition">Home</Link>
            <Link to="/products" className="hover:text-blue-600 transition">Products</Link>
            <Link to="/cart" className="hover:text-blue-600 transition">Cart ({cartCount})</Link>
            <Link to="/checkout" className="hover:text-blue-600 transition">Checkout</Link>
          </nav>
          <div className="flex items-center gap-2">
            <button onClick={() => navigate('/products?category=Women')} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">New Arrivals</button>
          </div>
        </div>
      </header>
    );
  };

  return (
    <div className="min-h-screen bg-gradient-to-b from-white via-blue-50 to-pink-50">
      <Navbar />

      {toast && (
        <div className="fixed top-20 right-4 z-40 bg-gray-900 text-white px-4 py-2 rounded-lg shadow-md">{toast}</div>
      )}

      <section className="max-w-6xl mx-auto px-4 pt-8 pb-4">
        <div className="rounded-xl p-6 md:p-8 bg-gradient-to-tr from-blue-600 via-fuchsia-500 to-amber-400 text-white shadow-md">
          <div className="flex flex-col md:flex-row items-center gap-6">
            <div className="flex-1">
              <h1 className="text-3xl md:text-4xl font-extrabold leading-tight">Color your wardrobe with styles that move</h1>
              <p className="mt-2 text-white/90">Discover vibrant essentials, premium fabrics, and feel-good fits. Free shipping over $75.</p>
              <div className="mt-4 flex gap-3">
                <button onClick={() => navigate('/products?category=Men')} className="px-4 py-2 rounded-lg bg-white text-gray-900 hover:bg-white/90 transition">Shop Men</button>
                <button onClick={() => navigate('/products?category=Women')} className="px-4 py-2 rounded-lg bg-gray-900 text-white hover:bg-gray-800 transition">Shop Women</button>
                <button onClick={() => navigate('/products')} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">View All</button>
              </div>
            </div>
            <div className="w-full md:w-1/2">
              <img className="w-full h-56 md:h-64 object-cover rounded-xl shadow-md" src="https://images.unsplash.com/photo-1512436991641-6745cdb1723f?w=1200&q=80&auto=format&fit=crop" alt="Colorful clothes on rack" />
            </div>
          </div>
        </div>
      </section>

      <section className="max-w-6xl mx-auto px-4 py-6">
        <div className="flex flex-wrap items-center justify-between gap-4">
          <div className="flex items-center gap-2 overflow-x-auto">
            {categories.map((c) => (
              <button
                key={c}
                onClick={() => setActive(c)}
                className={`px-4 py-2 rounded-lg shadow-md transition ${active === c ? 'bg-blue-600 text-white' : 'bg-white text-gray-700 hover:bg-gray-50'}`}
              >
                {c}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-3 w-full md:w-auto">
            <div className="flex-1 md:flex-none">
              <input
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder="Search products..."
                className="w-full md:w-64 px-4 py-2 rounded-lg border border-gray-300 bg-white shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
            <select
              value={sort}
              onChange={(e) => setSort(e.target.value as any)}
              className="px-3 py-2 rounded-lg border border-gray-300 bg-white shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="featured">Featured</option>
              <option value="price-asc">Price: Low to High</option>
              <option value="price-desc">Price: High to Low</option>
              <option value="rating">Top Rated</option>
            </select>
            <button onClick={() => navigate('/cart')} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Cart ({cartCount})</button>
          </div>
        </div>

        <div className="mt-6 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {filtered.map((p) => (
            <div
              key={p.id}
              id={`prod-${p.id}`}
              className="group bg-white rounded-xl shadow-md overflow-hidden hover:shadow-lg transition flex flex-col"
            >
              <div className="relative">
                <img
                  onClick={() => {
                    setSelected(p);
                    setQuickColor(p.colors[0] || '');
                  }}
                  src={p.image}
                  alt={p.name}
                  className="h-52 w-full object-cover cursor-pointer"
                />
                {p.tag && (
                  <span className="absolute top-3 left-3 text-xs font-semibold bg-white/90 text-gray-900 px-3 py-1 rounded-full shadow">{p.tag}</span>
                )}
                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition" />
              </div>
              <div className="p-4 flex flex-col gap-3 flex-1">
                <div className="flex items-start justify-between gap-2">
                  <div>
                    <h3 className="font-semibold text-gray-900">{p.name}</h3>
                    <div className="text-sm text-gray-500">{p.category}</div>
                  </div>
                  <div className="text-right">
                    <div className="font-bold text-gray-900">${p.price.toFixed(2)}</div>
                    <div className="text-xs text-amber-500">★ {p.rating.toFixed(1)}</div>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  {p.colors.map((c) => (
                    <span key={c} className="h-4 w-4 rounded-full border border-white shadow" style={{ backgroundColor: c }} />
                  ))}
                </div>
                <div className="mt-auto flex items-center gap-2">
                  <button onClick={() => addToCart(p, 1)} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Add to cart</button>
                  <button onClick={() => { addToCart(p, 1); navigate('/checkout'); }} className="px-4 py-2 rounded-lg bg-gray-900 text-white hover:bg-gray-800 transition">Buy now</button>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="mt-10 rounded-xl p-6 bg-white shadow-md flex flex-col md:flex-row items-center gap-6">
          <img className="w-full md:w-1/3 h-44 object-cover rounded-lg" src="https://images.unsplash.com/photo-1516251193007-45ef944ab0c6?w=1000&q=80&auto=format&fit=crop" alt="Denim rack" />
          <div className="flex-1">
            <h3 className="text-xl font-bold text-gray-900">Limited-time Drop: Indigo Denim</h3>
            <p className="text-gray-600 mt-1">Crafted for comfort with rich tones that fade beautifully. Save 15% today.</p>
            <div className="mt-3 flex gap-3">
              <button onClick={() => navigate('/products?category=Men')} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Explore Men</button>
              <button onClick={() => navigate('/cart')} className="px-4 py-2 rounded-lg bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 transition">Go to Cart</button>
            </div>
          </div>
        </div>
      </section>

      {selected && (
        <div className="fixed inset-0 z-40 flex">
          <div className="flex-1 bg-black/40" onClick={() => setSelected(null)} />
          <div className="w-full sm:w-[420px] bg-white h-full shadow-2xl p-6 overflow-y-auto">
            <div className="flex items-start justify-between">
              <div>
                <h4 className="text-lg font-bold text-gray-900">{selected.name}</h4>
                <div className="text-sm text-gray-500">{selected.category} • ★ {selected.rating.toFixed(1)}</div>
              </div>
              <button onClick={() => setSelected(null)} className="px-3 py-1 rounded-lg bg-gray-100 hover:bg-gray-200 transition">Close</button>
            </div>
            <img src={selected.image} alt={selected.name} className="mt-4 h-56 w-full object-cover rounded-xl shadow-md" />
            <div className="mt-4">
              <div className="text-2xl font-extrabold text-gray-900">${selected.price.toFixed(2)}</div>
              <p className="mt-2 text-gray-600">Premium feel, breathable fabric, and a color pop that elevates daily looks.</p>
              <div className="mt-4">
                <div className="text-sm text-gray-700 mb-1">Choose a color</div>
                <div className="flex items-center gap-2">
                  {selected.colors.map((c) => (
                    <button
                      key={c}
                      onClick={() => setQuickColor(c)}
                      className={`h-8 w-8 rounded-full ring-offset-2 transition ${quickColor === c ? 'ring-2 ring-blue-500' : ''}`}
                      style={{ backgroundColor: c }}
                      aria-label={`color ${c}`}
                    />
                  ))}
                </div>
              </div>
              <div className="mt-6 flex items-center gap-3">
                <button onClick={() => { addToCart(selected, 1); }} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Add to cart</button>
                <button onClick={() => { addToCart(selected, 1); navigate('/checkout'); }} className="px-4 py-2 rounded-lg bg-gray-900 text-white hover:bg-gray-800 transition">Buy now</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <footer className="mt-10 py-10">
        <div className="max-w-6xl mx-auto px-4 text-center text-sm text-gray-600">
          © {new Date().getFullYear()} Vibrato Cloth Co. All rights reserved.
        </div>
      </footer>
    </div>
  );
};

export default ProductList;

