import React, { useEffect, useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

type CartItem = {
  id: string;
  name: string;
  price: number;
  image: string;
  quantity: number;
};

const CART_KEY = 'app_cart';

const readCart = (): CartItem[] => {
  try {
    const raw = localStorage.getItem(CART_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch (e) {
    return [];
  }
};

const writeCart = (items: CartItem[]) => {
  localStorage.setItem(CART_KEY, JSON.stringify(items));
};

const Cart: React.FC = () => {
  const navigate = useNavigate();
  const [items, setItems] = useState<CartItem[]>([]);
  const [toast, setToast] = useState<string>('');

  useEffect(() => {
    setItems(readCart());
  }, []);

  useEffect(() => {
    const t = setTimeout(() => setToast(''), 1500);
    return () => clearTimeout(t);
  }, [toast]);

  const subtotal = useMemo(() => items.reduce((a, i) => a + i.price * i.quantity, 0), [items]);
  const shipping = subtotal > 75 ? 0 : 6.9;
  const total = subtotal + shipping;

  const updateQty = (id: string, delta: number) => {
    setItems((prev) => {
      const next = prev
        .map((i) => (i.id === id ? { ...i, quantity: i.quantity + delta } : i))
        .filter((i) => i.quantity > 0);
      writeCart(next);
      return next;
    });
  };

  const removeItem = (id: string) => {
    setItems((prev) => {
      const next = prev.filter((i) => i.id !== id);
      writeCart(next);
      return next;
    });
    setToast('Removed item');
  };

  const clearCart = () => {
    writeCart([]);
    setItems([]);
    setToast('Cart cleared');
  };

  const Navbar: React.FC = () => {
    return (
      <header className="sticky top-0 z-30 bg-white/80 backdrop-blur border-b border-gray-200">
        <div className="max-w-6xl mx-auto px-4 py-3 flex items-center justify-between">
          <div onClick={() => navigate('/')} className="flex items-center gap-2 cursor-pointer">
            <span className="inline-flex h-8 w-8 rounded-xl bg-gradient-to-tr from-blue-500 via-fuchsia-500 to-amber-400" />
            <span className="font-bold text-gray-900 text-lg">Vibrato Cloth Co.</span>
          </div>
          <nav className="hidden md:flex items-center gap-6 text-sm text-gray-700">
            <Link to="/" className="hover:text-blue-600 transition">Home</Link>
            <Link to="/products" className="hover:text-blue-600 transition">Products</Link>
            <Link to="/cart" className="hover:text-blue-600 transition">Cart ({items.reduce((a, b) => a + b.quantity, 0)})</Link>
            <Link to="/checkout" className="hover:text-blue-600 transition">Checkout</Link>
          </nav>
          <div className="flex items-center gap-2">
            <button onClick={() => navigate('/products')} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Continue Shopping</button>
          </div>
        </div>
      </header>
    );
  };

  return (
    <div className="min-h-screen bg-gradient-to-b from-white via-blue-50 to-pink-50">
      <Navbar />

      {toast && (
        <div className="fixed top-20 right-4 z-40 bg-gray-900 text-white px-4 py-2 rounded-lg shadow-md">{toast}</div>
      )}

      <section className="max-w-6xl mx-auto px-4 py-8">
        <h1 className="text-2xl font-extrabold text-gray-900">Your Cart</h1>
        {items.length === 0 ? (
          <div className="mt-8 bg-white rounded-xl shadow-md p-8 text-center">
            <p className="text-gray-600">Your cart is empty. Discover vibrant styles and add them to your bag.</p>
            <div className="mt-4">
              <button onClick={() => navigate('/products')} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Browse Products</button>
            </div>
          </div>
        ) : (
          <div className="mt-6 grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="lg:col-span-2 flex flex-col gap-4">
              {items.map((item) => (
                <div key={item.id} className="bg-white rounded-xl shadow-md p-4 flex gap-4 items-center">
                  <img src={item.image} alt={item.name} className="h-24 w-24 object-cover rounded-lg" />
                  <div className="flex-1">
                    <div className="flex items-start justify-between">
                      <div>
                        <h3 className="font-semibold text-gray-900">{item.name}</h3>
                        <div className="text-sm text-gray-500">${item.price.toFixed(2)}</div>
                      </div>
                      <button onClick={() => removeItem(item.id)} className="px-3 py-1 rounded-lg bg-gray-100 hover:bg-gray-200 transition">Remove</button>
                    </div>
                    <div className="mt-3 flex items-center gap-3">
                      <div className="inline-flex items-center rounded-lg border border-gray-200 overflow-hidden">
                        <button onClick={() => updateQty(item.id, -1)} className="px-3 py-1.5 hover:bg-gray-50">-</button>
                        <span className="px-3 py-1.5 text-sm">{item.quantity}</span>
                        <button onClick={() => updateQty(item.id, 1)} className="px-3 py-1.5 hover:bg-gray-50">+</button>
                      </div>
                      <div className="text-sm text-gray-600">Item total: <span className="font-semibold text-gray-900">${(item.price * item.quantity).toFixed(2)}</span></div>
                    </div>
                  </div>
                </div>
              ))}
              <div className="flex items-center gap-3">
                <button onClick={() => clearCart()} className="px-4 py-2 rounded-lg bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 transition">Clear Cart</button>
                <button onClick={() => navigate('/products')} className="px-4 py-2 rounded-lg bg-gray-900 text-white hover:bg-gray-800 transition">Add More Items</button>
              </div>
            </div>
            <div className="lg:col-span-1">
              <div className="bg-white rounded-xl shadow-md p-6 sticky top-24">
                <h3 className="text-lg font-bold text-gray-900">Order Summary</h3>
                <div className="mt-4 space-y-2 text-sm">
                  <div className="flex items-center justify-between"><span className="text-gray-600">Subtotal</span><span className="font-semibold text-gray-900">${subtotal.toFixed(2)}</span></div>
                  <div className="flex items-center justify-between"><span className="text-gray-600">Shipping</span><span className="font-semibold text-gray-900">{shipping === 0 ? 'Free' : `$${shipping.toFixed(2)}`}</span></div>
