import React, { useEffect, useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

type CartItem = {
  id: string;
  name: string;
  price: number;
  image: string;
  quantity: number;
};

const CART_KEY = 'app_cart';

const readCart = (): CartItem[] => {
  try {
    const raw = localStorage.getItem(CART_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch (e) {
    return [];
  }
};

const writeCart = (items: CartItem[]) => {
  localStorage.setItem(CART_KEY, JSON.stringify(items));
};

const Checkout: React.FC = () => {
  const navigate = useNavigate();
  const [cart, setCart] = useState<CartItem[]>([]);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [address, setAddress] = useState('');
  const [city, setCity] = useState('');
  const [country, setCountry] = useState('');
  const [shipping, setShipping] = useState<'standard' | 'express'>('standard');
  const [payMethod, setPayMethod] = useState<'card' | 'paypal'>('card');
  const [submitting, setSubmitting] = useState(false);
  const [orderId, setOrderId] = useState<string>('');

  useEffect(() => {
    setCart(readCart());
  }, []);

  const subtotal = useMemo(() => cart.reduce((a, i) => a + i.price * i.quantity, 0), [cart]);
  const shippingCost = shipping === 'standard' ? (subtotal > 75 ? 0 : 6.9) : 14.9;
  const total = subtotal + shippingCost;

  const valid = name.trim() && email.includes('@') && address.trim() && city.trim() && country.trim();

  const placeOrder = () => {
    if (!valid) return;
    setSubmitting(true);
    setTimeout(() => {
      const id = 'VX-' + Math.random().toString(36).slice(2, 7).toUpperCase();
      setOrderId(id);
      writeCart([]);
      setCart([]);
      setSubmitting(false);
    }, 1000);
  };

  const Navbar: React.FC = () => {
    return (
      <header className="sticky top-0 z-30 bg-white/80 backdrop-blur border-b border-gray-200">
