                  <div className="font-semibold text-gray-900">Standard</div>
                  <div className="text-sm text-gray-600">3-6 business days {subtotal > 75 ? '(Free)' : '($6.90)'}</div>
                </button>
                <button onClick={() => setShipping('express')} className={`p-4 rounded-xl border shadow-sm text-left transition ${shipping === 'express' ? 'border-blue-500 ring-2 ring-blue-100' : 'border-gray-200 hover:border-gray-300'}`}>
