                <button onClick={() => setPayMethod('paypal')} className={`px-4 py-2 rounded-lg border shadow-sm transition ${payMethod === 'paypal' ? 'border-blue-500 ring-2 ring-blue-100' : 'border-gray-200 hover:border-gray-300'}`}>PayPal</button>
